   ═══════════════════════════════════════ */

/* ── Nord Palette Reference ──
   Polar Night:  #2e3440  #3b4252  #434c5e  #4c566a
   Snow Storm:   #d8dee9  #e5e9f0  #eceff4
   Frost:        #8fbcbb  #88c0d0  #81a1c1  #5e81ac
   Aurora:       #bf616a  #d08770  #ebcb8b  #a3be8c  #b48ead
   ──────────────────────────────── */

/* ═══════════════════════════════════════
   Dark Mode (Nord Polar Night)
   ═══════════════════════════════════════ */
:root,
[data-theme="dark"] {
  /* ── Core ── */
  --background: #2e3440;
  --marinara-app-background-paint: var(--background);
  --foreground: #eceff4;
  --primary: #88c0d0;                     /* Nord Frost (teal) */
  --primary-foreground: #2e3440;
  --destructive: #bf616a;                 /* Nord Aurora (red) */
  --destructive-foreground: #eceff4;

  /* ── Surfaces ── */
  --card: #3b4252;
  --card-foreground: #eceff4;
  --secondary: #434c5e;
  --secondary-foreground: #d8dee9;
  --accent: #4c566a;
  --accent-foreground: #eceff4;
  --popover: #3b4252;
  --popover-foreground: #eceff4;

  /* ── Borders & Inputs ── */
  --border: #4c566a;
  --input: #3b4252;
  --ring: #88c0d0;

  /* ── Text ── */
  --muted: #434c5e;
  --muted-foreground: #d8dee9;

  /* ── Sidebar ── */
  --sidebar: #2e3440;
  --sidebar-foreground: #d8dee9;
  --sidebar-border: #3b4252;
  --sidebar-accent: #434c5e;
  --sidebar-accent-foreground: #88c0d0;

  /* ── App Accent ── */
  --marinara-app-accent-solid: var(--primary);
  --marinara-app-accent-gradient: linear-gradient(
    90deg,
    var(--marinara-app-accent-solid),
    color-mix(in srgb, var(--marinara-app-accent-solid) 76%, var(--foreground) 24%),
    var(--marinara-app-accent-solid)
  );

  /* ── Chat Mode Logo Colors ──
     The sidebar [+] button, mode tabs, and chat
     mode badges use these gradient pairs.
     Defaults are bright cyan/orange/pink.
     Remapped to muted Nord Frost + Aurora. */
  --mari-logo-cyan: #88c0d0;
  --mari-logo-cyan-deep: #5e81ac;
  --mari-logo-orange: #d08770;
  --mari-logo-orange-deep: #b48ead;
  --mari-logo-pink: #b48ead;
  --mari-logo-pink-deep: #5e81ac;
  --mari-logo-title-cyan: #88c0d0;
  --mari-logo-title-orange: #d08770;
  --mari-logo-title-pink: #b48ead;

  /* ── Shell Chrome ── */
  --marinara-topbar-surface: color-mix(in srgb, var(--card) 80%, transparent);
  --marinara-shell-edge-border: color-mix(in srgb, var(--foreground) 14%, var(--background) 86%);

  /* ── Shared Chat / Roleplay / Game Chrome ── */
  --marinara-chat-chrome-accent: var(--marinara-app-accent-solid);
  --marinara-chat-chrome-accent-gradient: var(--marinara-app-accent-gradient);
  --marinara-chat-chrome-text: var(--foreground);
  --marinara-chat-chrome-button-text-base: var(--marinara-chat-chrome-accent);
  --marinara-chat-chrome-highlight-text-base: var(--marinara-chat-chrome-accent);

  --marinara-chat-chrome-surface-bg: var(--card);
  --marinara-chat-chrome-surface-bg-hover: color-mix(
    in srgb, var(--marinara-chat-chrome-surface-bg) 92%, var(--foreground) 8%);
  --marinara-chat-chrome-surface-bg-active: color-mix(
    in srgb, var(--marinara-chat-chrome-surface-bg) 88%, var(--foreground) 12%);

  --marinara-chat-chrome-button-bg: var(--marinara-chat-chrome-surface-bg);
  --marinara-chat-chrome-button-bg-hover: color-mix(
    in srgb, var(--marinara-chat-chrome-surface-bg-hover) 90%, var(--marinara-chat-chrome-accent) 10%);
  --marinara-chat-chrome-button-bg-active: color-mix(
    in srgb, var(--marinara-chat-chrome-surface-bg-active) 84%, var(--marinara-chat-chrome-accent) 16%);
  --marinara-chat-chrome-button-border: color-mix(
    in srgb, var(--marinara-chat-chrome-accent) 12%, transparent);
  --marinara-chat-chrome-button-border-hover: color-mix(
    in srgb, var(--marinara-chat-chrome-accent) 20%, transparent);
  --marinara-chat-chrome-button-border-active: color-mix(
    in srgb, var(--marinara-chat-chrome-accent) 24%, transparent);
  --marinara-chat-chrome-button-text: color-mix(
    in srgb, var(--marinara-chat-chrome-button-text-base) 64%, transparent);
  --marinara-chat-chrome-button-text-hover: color-mix(
    in srgb, var(--marinara-chat-chrome-button-text-base) 92%, transparent);
  --marinara-chat-chrome-button-text-active: color-mix(
    in srgb, var(--marinara-chat-chrome-button-text-base) 96%, transparent);

  --marinara-chat-chrome-panel-bg: var(--marinara-chat-chrome-button-bg);
  --marinara-chat-chrome-panel-border: color-mix(
    in srgb, var(--marinara-chat-chrome-accent) 16%, transparent);
  --marinara-chat-chrome-panel-divider: color-mix(
    in srgb, var(--marinara-chat-chrome-accent) 13%, transparent);
  --marinara-chat-chrome-panel-text: color-mix(
    in srgb, var(--marinara-chat-chrome-text) 90%, transparent);
  --marinara-chat-chrome-panel-title: color-mix(
    in srgb, var(--marinara-chat-chrome-text) 96%, transparent);
  --marinara-chat-chrome-panel-muted: color-mix(
    in srgb, var(--marinara-chat-chrome-text) 58%, transparent);

  --marinara-chat-chrome-highlight-bg: color-mix(
    in srgb, var(--marinara-chat-chrome-accent) 9%, transparent);
  --marinara-chat-chrome-highlight-bg-hover: color-mix(
    in srgb, var(--marinara-chat-chrome-accent) 13%, transparent);
  --marinara-chat-chrome-highlight-text: color-mix(
    in srgb, var(--marinara-chat-chrome-highlight-text-base) 94%, transparent);

  --marinara-chat-chrome-input-bg: var(--marinara-chat-chrome-surface-bg);
  --marinara-chat-chrome-input-border: color-mix(
    in srgb, var(--marinara-chat-chrome-accent) 14%, transparent);
  --marinara-chat-chrome-input-border-focus: color-mix(
    in srgb, var(--marinara-chat-chrome-accent) 30%, transparent);

  /* ── Tailwind Palette Remap ──
     The engine hardcodes Tailwind color classes
     (from-pink-400, text-amber-300, etc.) for accent
     gradients, status badges, and menu icons.
     These overrides remap each hue family to a Nord
     equivalent — muted, cool-toned, cohesive. */
  --color-pink-300: #c29bb7;
  --color-pink-400: #b48ead;
  --color-pink-500: #a17b9b;
  --color-rose-200: #dfa8ad;
  --color-rose-300: #ce8d93;
  --color-rose-400: #c97981;
  --color-rose-500: #bf616a;
  --color-red-200: #dfa8ad;
  --color-red-300: #ce8d93;
  --color-red-400: #c97981;
  --color-red-500: #bf616a;
  --color-red-600: #b05560;
  --color-amber-200: #f1d59f;
  --color-amber-300: #ebcb8b;
  --color-amber-400: #d9b671;
  --color-amber-500: #c9a94e;
  --color-orange-200: #e8c1b3;
  --color-orange-300: #dca695;
  --color-orange-400: #d08770;
  --color-orange-500: #c47a64;
  --color-emerald-300: #b1c79e;
  --color-emerald-400: #a3be8c;
  --color-emerald-500: #8ea778;
  --color-teal-400: #8fbcbb;
  --color-teal-500: #7dacab;
  --color-green-400: #a3be8c;
  --color-green-500: #8ea778;
  --color-lime-400: #a3be8c;
  --color-cyan-200: #b8dce6;
  --color-cyan-300: #a6d2de;
  --color-cyan-400: #9ccbd8;
  --color-cyan-500: #88c0d0;
  --color-sky-300: #9ccbd8;
  --color-sky-400: #88c0d0;
  --color-sky-500: #7eb2c2;
  --color-blue-300: #96b6d0;
  --color-blue-400: #81a1c1;
  --color-blue-500: #5e81ac;
  --color-violet-200: #dbcdd8;
  --color-violet-300: #caacc5;
  --color-violet-400: #b48ead;
  --color-violet-500: #a17b9b;
  --color-purple-300: #c29bb7;
  --color-purple-400: #b48ead;
  --color-purple-500: #a17b9b;
  --color-fuchsia-300: #caacc5;
  --color-fuchsia-400: #b48ead;
  --color-fuchsia-500: #a17b9b;
  --color-gray-400: #6e7a8a;
  --color-gray-500: #4c566a;

  /* ── Decorative Palette ── */
  --y2k-pink: #88c0d0;
  --y2k-purple: #b48ead;
  --y2k-blue: #81a1c1;
  --y2k-mint: #a3be8c;
  --y2k-peach: #d08770;
  --y2k-lavender: #b48ead;
  --y2k-yellow: #ebcb8b;
  --pastel-rose: #dfa8ad;
  --pastel-lilac: #dbcdd8;
  --pastel-sky: #b8dce6;
  --pastel-mint: #cde0bc;
  --pastel-coral: #e8c1b3;
  --pastel-peach: #e8c1b3;
  --pastel-lavender: #cdbece;
  --pastel-periwinkle: #b4c2da;
  --rgb-red: #bf616a;
  --rgb-orange: #d08770;
  --rgb-yellow: #ebcb8b;
  --rgb-green: #a3be8c;
  --rgb-cyan: #88c0d0;
  --rgb-blue: #81a1c1;
  --rgb-indigo: #b48ead;
  --rgb-violet: #b48ead;

  /* ── Cursor ── */
  --cursor-pink: url("data:image/svg+xml,%3Csvg width='24' height='24' viewBox='0 0 24 24' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M3 3L10 20L12 12L20 10L3 3Z' fill='%2388c0d0' stroke='%232e3440' stroke-width='1'/%3E%3C/svg%3E");
}

/* ═══════════════════════════════════════
   Light Mode (Nord Snow Storm)
   ═══════════════════════════════════════ */
[data-theme="light"] {
  /* ── Core ── */
  --background: #eceff4;
  --marinara-app-background-paint: var(--background);
  --foreground: #2e3440;
  --primary: #5e81ac;                     /* Nord Frost (darker blue) */
  --primary-foreground: #eceff4;
  --destructive: #bf616a;
  --destructive-foreground: #eceff4;

  /* ── Surfaces ── */
  --card: #e5e9f0;
  --card-foreground: #2e3440;
  --secondary: #d8dee9;
  --secondary-foreground: #3b4252;
  --accent: #d8dee9;
  --accent-foreground: #2e3440;
  --popover: #e5e9f0;
  --popover-foreground: #2e3440;

  /* ── Borders & Inputs ── */
  --border: #d8dee9;
  --input: #e5e9f0;
  --ring: #5e81ac;

  /* ── Text ── */
  --muted: #d8dee9;
  --muted-foreground: #4c566a;

  /* ── Sidebar ── */
  --sidebar: #eceff4;
  --sidebar-foreground: #3b4252;
  --sidebar-border: #d8dee9;
  --sidebar-accent: #c4cad7;
  --sidebar-accent-foreground: #5e81ac;

  /* ── App Accent ── */
  --marinara-app-accent-solid: var(--primary);
  --marinara-app-accent-gradient: linear-gradient(
    90deg,
    var(--marinara-app-accent-solid),
    color-mix(in srgb, var(--marinara-app-accent-solid) 76%, var(--foreground) 24%),
    var(--marinara-app-accent-solid)
  );

  /* ── Chat Mode Logo Colors (light mode) ── */
