  --mari-logo-cyan-deep: #4c6a90;
  --mari-logo-orange: #d08770;
  --mari-logo-orange-deep: #bf616a;
  --mari-logo-pink: #b48ead;
  --mari-logo-pink-deep: #5e81ac;
  --mari-logo-title-cyan: #5e81ac;
  --mari-logo-title-orange: #d08770;
  --mari-logo-title-pink: #b48ead;

  /* ── Tailwind Palette Remap (light mode) ── */
