  --color-red-600: #6d3a41;
  --color-amber-200: #d9b671;
  --color-amber-300: #c9a94e;
  --color-amber-400: #b89436;
  --color-amber-500: #a07f29;
  --color-orange-200: #dca695;
  --color-orange-300: #d08770;
  --color-orange-400: #c47a64;
  --color-orange-500: #a86552;
  --color-emerald-300: #a3be8c;
  --color-emerald-400: #8ea778;
  --color-emerald-500: #718564;
  --color-teal-400: #8fbcbb;
  --color-teal-500: #7dacab;
  --color-green-400: #8ea778;
  --color-green-500: #718564;
  --color-lime-400: #8ea778;
  --color-cyan-200: #9ccbd8;
  --color-cyan-300: #88c0d0;
  --color-cyan-400: #7eb2c2;
  --color-cyan-500: #5f8e9a;
  --color-sky-300: #88c0d0;
  --color-sky-400: #7eb2c2;
  --color-sky-500: #5f8e9a;
  --color-blue-300: #81a1c1;
  --color-blue-400: #5e81ac;
  --color-blue-500: #4e6d94;
  --color-violet-200: #caacc5;
  --color-violet-300: #b48ead;
  --color-violet-400: #a17b9b;
  --color-violet-500: #8e6c8a;
  --color-purple-300: #b48ead;
  --color-purple-400: #a17b9b;
  --color-purple-500: #8e6c8a;
  --color-fuchsia-300: #b48ead;
  --color-fuchsia-400: #a17b9b;
  --color-fuchsia-500: #8e6c8a;
  --color-gray-400: #6e7a8a;
  --color-gray-500: #4c566a;

  /* ── Palette (decorative) ── */
  --y2k-pink: #5e81ac;
  --y2k-purple: #b48ead;
  --y2k-blue: #5e81ac;
