}

/* ═══════════════════════════════════════
   Message Action Buttons + Swipe Pager
   Styles the pill-shaped action bar below
   messages and the swipe-indicator between
   message text and actions.

   Requires me-themehelper for .themed-action-button
   classes on the buttons inside.
   ═══════════════════════════════════════ */

/* ── Action Bar Pill ── */
.mari-app .mari-message-actions {
  display: inline-flex !important;
  align-items: center;
  justify-content: flex-start;
  align-self: flex-start !important;
  flex: 0 0 auto;
  width: fit-content !important;
  max-width: calc(100vw - 1.25rem);
  gap: 0.2rem;
  padding: 0.2rem 0.35rem;
  border-radius: 9999px;
  background: color-mix(in srgb, var(--secondary) 42%, var(--card) 58%);
  border: 1px solid color-mix(in srgb, var(--primary) 15%, transparent);
  transition: background-color 140ms ease, border-color 140ms ease;
}

.mari-app .mari-message-actions.flex-row-reverse {
  align-self: flex-end !important;
}

/* ── Buttons Inside the Pill ── */
.mari-app .mari-message-actions .themed-action-button {
  display: inline-flex !important;
  align-items: center !important;
  justify-content: center !important;
  min-width: 1.75rem !important;
  min-height: 1.75rem !important;
  padding: 0.25rem !important;
  border-radius: 9999px !important;
  background: transparent !important;
  border: none !important;
  outline: none !important;
  box-shadow: none !important;
  color: var(--muted-foreground) !important;
  line-height: 1;
  transition: background-color 140ms ease, color 140ms ease;
}

.mari-app .mari-message-actions .themed-action-button:hover {
  background: color-mix(in srgb, var(--primary) 10%, transparent) !important;
  color: var(--foreground) !important;
}

.mari-app .mari-message-actions .themed-action-button:is(:focus-visible, :active) {
  background: color-mix(in srgb, var(--primary) 10%, transparent) !important;
  color: var(--foreground) !important;
}

/* ── Guided State (character-triggered action) ── */
.mari-app .mari-message-actions .themed-action-button.guided {
  color: var(--primary) !important;
  background: color-mix(in srgb, var(--primary) 12%, transparent) !important;
  box-shadow: 0 0 10px color-mix(in srgb, var(--primary) 35%, transparent) !important;
}

.mari-app .mari-message-actions .themed-action-button.guided:hover {
  background: color-mix(in srgb, var(--primary) 20%, transparent) !important;
  box-shadow: 0 0 14px color-mix(in srgb, var(--primary) 50%, transparent) !important;
}

/* Kill border bleed from themed-action-bar on SVG icons */
.mari-app .mari-message-actions svg.themed-action-bar,
.mari-app .mari-message-actions svg.themed-action-bar * {
  border: none !important;
  background: transparent !important;
}

/* ── Swipe Pager Pill ── */
.mari-app .mari-message-swipes {
  display: inline-flex !important;
  align-items: center;
  justify-content: flex-start;
  align-self: flex-start;
  flex: 0 0 auto;
  width: fit-content !important;
  max-width: max-content;
  gap: 0.3rem;
  padding: 0.2rem 0.45rem;
  min-height: 1.6rem;
  border-radius: 9999px;
  background: color-mix(in srgb, var(--secondary) 38%, var(--card) 62%) !important;
  border: 1px solid color-mix(in srgb, var(--primary) 18%, transparent);
  color: var(--muted-foreground) !important;
  font-size: 0.75rem !important;
}

.mari-app .mari-message-swipes > button {
  min-width: 1.35rem !important;
  min-height: 1.35rem !important;
  padding: 0.15rem !important;
  border-radius: 9999px !important;
  background: color-mix(in srgb, var(--secondary) 55%, transparent);
  color: var(--muted-foreground) !important;
}

.mari-app .mari-message-swipes > button:hover:not(:disabled) {
  background: color-mix(in srgb, var(--primary) 12%, transparent) !important;
}

.mari-app .mari-message-swipes > button:disabled {
  opacity: 0.45 !important;
}

.mari-app .mari-message-swipes > button > svg {
  width: 0.95rem !important;
  height: 0.95rem !important;
}

.mari-app .mari-message-swipes .tabular-nums {
  min-width: 2.1rem;
  text-align: center;
  letter-spacing: 0.02em;
  color: var(--foreground) !important;
}

/* ═══════════════════════════════════════
   Panel Gradient Accents
   The engine ships bright Tailwind gradients
   for sidebar panel icons, TopBar underlines,
   and CTA buttons. Remapped to muted Nord
   Frost + Aurora hues.
   ═══════════════════════════════════════ */
.mari-panel-gradient--characters {
  --mari-panel-gradient-start: #88c0d0;
  --mari-panel-gradient-end: #5e81ac;
  --mari-panel-gradient-text: #eceff4;
}
.mari-panel-gradient--lorebooks {
  --mari-panel-gradient-start: #ebcb8b;
  --mari-panel-gradient-end: #d08770;
  --mari-panel-gradient-text: #2e3440;
}
.mari-panel-gradient--presets {
  --mari-panel-gradient-start: #b48ead;
  --mari-panel-gradient-end: #5e81ac;
  --mari-panel-gradient-text: #eceff4;
}
.mari-panel-gradient--connections {
  --mari-panel-gradient-start: #88c0d0;
  --mari-panel-gradient-end: #81a1c1;
  --mari-panel-gradient-text: #2e3440;
}
.mari-panel-gradient--agents {
  --mari-panel-gradient-start: #81a1c1;
  --mari-panel-gradient-end: #b48ead;
  --mari-panel-gradient-text: #eceff4;
}
.mari-panel-gradient--personas {
  --mari-panel-gradient-start: #a3be8c;
  --mari-panel-gradient-end: #8fbcbb;
  --mari-panel-gradient-text: #2e3440;
}
.mari-panel-gradient--browser {
  --mari-panel-gradient-start: #a3be8c;
  --mari-panel-gradient-end: #88c0d0;
  --mari-panel-gradient-text: #2e3440;
}

/* ═══════════════════════════════════════
   Roleplay Bubble Borders
   Default engine uses white ring-1 outlines.
   Replaced with the chat chrome accent so
   bubble edges match the Nord palette and
   defer to character highlight colours when
   card CSS is active.
   ═══════════════════════════════════════ */
[data-chat-mode="roleplay"] .mari-message-bubble {
  --tw-ring-color: color-mix(in srgb, var(--marinara-chat-chrome-accent) 16%, transparent) !important;
}
